            } catch {
                fullMessage += "\nPayload (serialization error): \(payload)"
            }
        }

        NSLog("%@", fullMessage) // Use NSLog for better integration with Console.app and crash reports
        print(fullMessage) // Also print for immediate Xcode console visibility
    }

