            if let jsonBody = body as? [String: Any],
               let data = try? JSONSerialization.data(withJSONObject: jsonBody, options: .prettyPrinted),
               let jsonString = String(data: data, encoding: .utf8) {
                payload["body"] = jsonString
            } else if let stringBody = body as? String {
                payload["body"] = stringBody
            } else {
                payload["body"] = String(describing: body)
            }
        }
        log(category: "API", message: "API Request to \(endpoint)", detailedPayload: payload)
    }

    func logAPIResponse(endpoint: String, method: String, statusCode: Int, userId: String? = nil, email: String? = nil, responseTimeMs: Double? = nil, responseBody: Any? = nil, error: Error? = nil) {
